console.log("APP START");

window.onload = () => {

  console.log("WINDOW LOADED");

  // 1. Проверка Leaflet
  if (typeof L === "undefined") {
    console.error("Leaflet NOT LOADED");
    return;
  }

  // 2. Создание карты
  const map = L.map("map").setView([41.8781, -87.6298], 11);

  L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
    attribution: "&copy; OpenStreetMap contributors"
  }).addTo(map);

  console.log("MAP READY");

  // 3. ТЕСТОВЫЕ МАРКЕРЫ (всегда работают)
  const fallback = [
    { name: "Chicago Downtown", lat: 41.8781, lng: -87.6298 },
    { name: "Navy Pier", lat: 41.8917, lng: -87.6078 },
    { name: "Museum Campus", lat: 41.8663, lng: -87.6170 }
  ];

  fallback.forEach(p => {
    L.marker([p.lat, p.lng])
      .addTo(map)
      .bindPopup(`<b>${p.name}</b>`);
  });

  console.log("FALLBACK MARKERS LOADED");

  // 4. JSON загрузка (если есть файл)
  fetch("./locations.json")
    .then(res => {
      console.log("FETCH STATUS:", res.status);

      if (!res.ok) {
        throw new Error("JSON not found");
      }

      return res.json();
    })
    .then(data => {

      console.log("DATA LOADED:", data);

      // очищаем fallback (опционально)
      data.forEach(loc => {

        if (!loc.lat || !loc.lng) {
          console.log("SKIP:", loc);
          return;
        }

        L.marker([loc.lat, loc.lng])
          .addTo(map)
          .bindPopup(`
            <b>${loc.name || "No name"}</b><br>
            ${loc.year || ""}
          `);

      });

      console.log("JSON MARKERS ADDED");

    })
    .catch(err => {
      console.warn("USING FALLBACK DATA ONLY:", err.message);
    });

};
